import Foundation

struct Stock {
    let symbol: String
    let price: Double
}

class Portfolio {
    private var stocks = [Stock]()

    func addStock(stock: Stock) {
        self.stocks.append(stock)
    }

    func removeStock(stock: Stock) {
        self.stocks.removeAll(where: { $0.symbol == stock.symbol })
    }
}

protocol ApiProtocol {
    func executeTrade(stock: Stock, completion: @escaping (Result<Bool, Error>) -> Void)
}

class Api: ApiProtocol {
    func executeTrade(stock: Stock, completion: @escaping (Result<Bool, Error>) -> Void) {
        // HTTP call to execute trade
        // For simplicity, we assume that the trade is always successful
        completion(.success(true))
    }
}

class TradingApplication {
    let api: ApiProtocol = Api()
    let portfolio = Portfolio()

    func buy(stock: Stock) {
        self.api.executeTrade(stock: stock) { result in
            switch result {
            case .success:
                self.portfolio.addStock(stock: stock)
            case .failure(let error):
                print("Error buying stock: \(error)")
            }
        }
    }
}